export const MoodIcon = ({ mood, ...props }: { mood: string } & MoodIconProps) => {
  switch (mood) {
    case 'stressed': return <StressedIcon {...props} />;
    case 'sad': return <SadIcon {...props} />;
    case 'tired': return <TiredIcon {...props} />;
    case 'okay': return <OkayIcon {...props} />;
    case 'focused': return <FocusedIcon {...props} />;
    case 'calm': return <CalmIcon {...props} />;
    case 'happy': return <HappyIcon {...props} />;
    case 'excited': return <ExcitedIcon {...props} />;
    default: return <OkayIcon {...props} />;
  }
};
